class CustomContinuationInterceptorMemoryLeakTest : TestBase() {

    @Test
    fun `test no leak when withContext completes without suspending`() = runTest {
        lateinit var ref: WeakReference<CoroutineName>
        val customInterceptor = CustomContinuationInterceptor(Dispatchers.Default)

        val job = GlobalScope.launch(customInterceptor) {
            val coroutineName = CoroutineName("TestCoroutine")
            ref = WeakReference(coroutineName)
            withContext(coroutineName) {
                // Complete without suspending
            }
        }
        job.join()

        System.gc()
        assertNull(ref.get(), "CoroutineName should have been garbage collected")
    }

    @Test
    fun `test no leak when withContext completes with suspending`() = runTest {
        lateinit var ref: WeakReference<CoroutineName>
        val customInterceptor = CustomContinuationInterceptor(Dispatchers.Default)

        val job = GlobalScope.launch(customInterceptor) {
            val coroutineName = CoroutineName("TestCoroutine")
            ref = WeakReference(coroutineName)
            withContext(coroutineName) {
                delay(1)
            }
        }
        job.join()

        System.gc()
        assertNull(ref.get(), "CoroutineName should have been garbage collected")
    }

    @Test
    fun `test no leak when withContext throws exception without suspending`() = runTest {
        lateinit var ref: WeakReference<CoroutineName>
        val customInterceptor = CustomContinuationInterceptor(Dispatchers.Default)

        val job = GlobalScope.launch(customInterceptor) {
            val coroutineName = CoroutineName("TestCoroutine")
            ref = WeakReference(coroutineName)
            try {
                withContext(coroutineName) {
                    throw TestException("Test")
                }
            } catch (e: TestException) {
                // Expected
            }
        }
        job.join()

        System.gc()
        assertNull(ref.get(), "CoroutineName should have been garbage collected")
    }

    @Test
    fun `test no leak with nested withContext calls`() = runTest {
        lateinit var ref1: WeakReference<CoroutineName>
        lateinit var ref2: WeakReference<CoroutineName>
        val customInterceptor = CustomContinuationInterceptor(Dispatchers.Default)

        val job = GlobalScope.launch(customInterceptor) {
            val coroutineName1 = CoroutineName("TestCoroutine1")
            ref1 = WeakReference(coroutineName1)
            withContext(coroutineName1) {
                val coroutineName2 = CoroutineName("TestCoroutine2")
                ref2 = WeakReference(coroutineName2)
                withContext(coroutineName2) {
                    // Complete without suspending
                }
            }
        }
        job.join()

        System.gc()
        assertNull(ref1.get(), "CoroutineName1 should have been garbage collected")
        assertNull(ref2.get(), "CoroutineName2 should have been garbage collected")
    }

    @Test
    fun `test no leak with multiple sequential withContext calls`() = runTest {
        val refs = mutableListOf<WeakReference<CoroutineName>>()
        val customInterceptor = CustomContinuationInterceptor(Dispatchers.Default)

        val job = GlobalScope.launch(customInterceptor) {
            repeat(10) { i ->
                val coroutineName = CoroutineName("TestCoroutine$i")
                refs.add(WeakReference(coroutineName))
                withContext(coroutineName) {
                    // Complete without suspending
                }
            }
        }
        job.join()

        System.gc()
        refs.forEach { ref ->
            assertNull(ref.get(), "All CoroutineNames should have been garbage collected")
        }
    }

    private class TestException(message: String) : Exception(message)
}

class CustomContinuationInterceptor(private val delegate: ContinuationInterceptor) :
